#include <iostream>
#include <vector>

// Function to reverse an array in-place
void reverseArray(int arr[], int size) {
    int left = 0;
    int right = size - 1;
    while (left < right) {
        int temp = arr[left];
        arr[left] = arr[right];
        arr[right] = temp;
        left++;
        right--;
    }
}

// Helper function to print an array
void printArray(const int arr[], int size) {
    for (int i = 0; i < size; ++i) {
        std::cout << arr[i] << (i == size - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

int main() {
    // Test Case 1
    int arr1[] = {1, 2, 3, 4, 5};
    int size1 = sizeof(arr1) / sizeof(arr1[0]);
    std::cout << "Original array 1: ";
    printArray(arr1, size1);
    reverseArray(arr1, size1);
    std::cout << "Reversed array 1: ";
    printArray(arr1, size1);

    // Test Case 2
    int arr2[] = {10, 20, 30};
    int size2 = sizeof(arr2) / sizeof(arr2[0]);
    std::cout << "Original array 2: ";
    printArray(arr2, size2);
    reverseArray(arr2, size2);
    std::cout << "Reversed array 2: ";
    printArray(arr2, size2);

    // Test Case 3
    int arr3[] = {7};
    int size3 = sizeof(arr3) / sizeof(arr3[0]);
    std::cout << "Original array 3: ";
    printArray(arr3, size3);
    reverseArray(arr3, size3);
    std::cout << "Reversed array 3: ";
    printArray(arr3, size3);

    // Test Case 4 (empty array)
    int arr4[] = {};
    int size4 = 0;
    std::cout << "Original array 4 (empty): ";
    printArray(arr4, size4);
    reverseArray(arr4, size4);
    std::cout << "Reversed array 4 (empty): ";
    printArray(arr4, size4);

    return 0;
}
